//! # Academorix dashboard — desktop shell library crate.
//!
//! This is the beating heart of the Tauri shell. Every entrypoint (the
//! plain `academorix-dashboard` binary in `main.rs`, the mobile targets
//! generated by `cargo tauri android/ios`, and integration tests) ends up
//! calling [`run`]. Keep the code here — do not duplicate the builder
//! wiring in `main.rs`.
//!
//! ## Responsibilities
//!
//! 1. Boot the Tauri v2 [`tauri::Builder`], attach the Phase 1/2 plugins
//!    (window-state, log), and register the base ACL manifest declared in
//!    `capabilities/default.json`.
//! 2. Build the platform-neutral native application menu (macOS/Windows/
//!    Linux) from the seed labels defined in `menu::build_menu`, and wire
//!    the click handler that forwards each command id to the renderer as
//!    an `menu-command` event.
//! 3. Register the system-tray icon (macOS: template-style menu-bar icon;
//!    Windows: system tray; Linux: best-effort — some DEs disable trays).
//! 4. Register the `menu_command` invoke handler used by the renderer to
//!    ask the shell to fire a Rust-side action (Phase 2 wire-up scaffold —
//!    real handlers land in Phase 3).
//! 5. Optionally attach the Phase 3 plugins (notification, shell, dialog,
//!    fs, deep-link, global-shortcut) when the `phase3` cargo feature is
//!    enabled. Toggling `phase4` on top adds the auto-updater plugin.
//!
//! ## Extending
//!
//! - New Phase 1/2 plugins go in [`register_plugins`].
//! - New menu categories go in [`menu::build_menu`] — the seed labels
//!   there deliberately match the `MenuCategory` enum in
//!   `src/config/menu.config.ts` so a renderer that talks to us over IPC
//!   knows what it is looking at.
//! - New IPC commands from the renderer go into [`commands::menu_command`]
//!   (or a fresh sibling module) and get added to `tauri::generate_handler!`.

// Modules kept alongside `lib.rs` so both `main.rs` and integration tests
// can pull them in via the library crate.
mod commands;
mod menu;
mod tray;

// Phase 3 stubs — always present in the module graph so `mod` declarations
// compile regardless of feature state. Their `pub fn init` entrypoints are
// gated at the item level so they only exist when `phase3` is enabled.
mod deep_link;
mod notification;
mod shortcut;

// The build-time-generated constants file. `build.rs` emits this into
// `$OUT_DIR/desktop_config.rs` after reading `desktop-config.json`. Keeping
// the include in `lib.rs` (not in a submodule) so every downstream module
// can reach the constants via `crate::WINDOW_WIDTH` etc.
include!(concat!(env!("OUT_DIR"), "/desktop_config.rs"));

use tauri::{AppHandle, Emitter, Listener, RunEvent};

/// Payload emitted on `menu-command` when the user activates a menu item.
/// Renderer-side type: `{ id: string, source: "native" | "tray" }`. Keeping
/// the wire format simple so the TypeScript adapter in
/// `src/desktop/native-menu.ts` can deserialize with `zod` without a custom
/// discriminator.
#[derive(Debug, Clone, serde::Serialize)]
pub(crate) struct MenuCommandPayload {
    pub id: String,
    pub source: &'static str,
}

/// Boots the Tauri app. The `#[cfg_attr]` below is the standard Tauri v2
/// mobile-entrypoint annotation — required when the crate is compiled for
/// iOS/Android via `cargo tauri android/ios`.
#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    // Compose the builder in phases so downstream contributors can add
    // plugins and features without touching the final `.run()` call.
    let builder = register_plugins(tauri::Builder::default())
        .invoke_handler(tauri::generate_handler![commands::menu_command])
        .setup(setup);

    builder
        .build(tauri::generate_context!())
        .expect("failed to build Academorix desktop shell — verify tauri.conf.json + desktop-config.json + capabilities/*.json are well-formed")
        .run(on_run_event);
}

/// Attaches every plugin the shell depends on. Split out from [`run`] so
/// integration tests can build a lookalike app without the plugins if they
/// want to.
fn register_plugins<R: tauri::Runtime>(builder: tauri::Builder<R>) -> tauri::Builder<R> {
    // ---- Phase 1/2 plugins (always on) ----
    //
    // `tauri-plugin-log` writes structured logs to the OS-standard directory
    // (`~/Library/Logs/<bundle-id>` on macOS, `%APPDATA%\<bundle-id>\logs`
    // on Windows, `$XDG_DATA_HOME/<bundle-id>/logs` on Linux). Level is
    // pulled from the generated `LOG_LEVEL` constant so ops can tune it
    // via `desktop.config.ts` without a Rust rebuild-of-the-source-tree.
    let builder = builder
        .plugin(
            tauri_plugin_log::Builder::default()
                .level(LOG_LEVEL)
                .build(),
        )
        // `tauri-plugin-window-state` persists window position + size
        // across launches — respected by `main.rs` when the user reopens
        // the app.
        .plugin(tauri_plugin_window_state::Builder::default().build());

    // ---- Phase 3 plugins (behind cargo feature) ----
    //
    // Deep-link + notification + fs + shell + dialog + global-shortcut land
    // in Phase 3. Their runtime wiring lives in the sibling stub modules
    // (`deep_link.rs`, `notification.rs`, `shortcut.rs`); the plugin
    // registration itself is a one-liner gated on the feature flag.
    #[cfg(feature = "phase3")]
    let builder = builder
        .plugin(tauri_plugin_notification::init())
        .plugin(tauri_plugin_shell::init())
        .plugin(tauri_plugin_dialog::init())
        .plugin(tauri_plugin_fs::init())
        .plugin(tauri_plugin_deep_link::init())
        .plugin(tauri_plugin_global_shortcut::Builder::new().build());

    // ---- Phase 4 plugin (behind cargo feature) ----
    //
    // Auto-updater. Requires signed builds — see `DESKTOP_OPS.md` for the
    // ops workflow.
    #[cfg(feature = "phase4")]
    let builder = builder.plugin(tauri_plugin_updater::Builder::new().build());

    builder
}

/// One-shot setup called after the builder has attached every plugin.
/// Runs on the main thread; blocking work should be spawned onto a
/// worker thread (`tauri::async_runtime::spawn`).
fn setup(app: &mut tauri::App) -> Result<(), Box<dyn std::error::Error>> {
    log::info!(
        "Academorix desktop shell booting — window={}x{}, tray={}, updater={}",
        WINDOW_WIDTH as u32,
        WINDOW_HEIGHT as u32,
        TRAY_ENABLED,
        UPDATER_ENABLED,
    );

    // 1. Native application menu bar. Always constructed — the menu is a
    //    no-op on Linux DEs that don't render it.
    menu::install_menu(app.handle())?;

    // 2. System tray. Guarded on the desktop_config flag; the helper
    //    itself no-ops on unsupported platforms.
    if TRAY_ENABLED {
        tray::install_tray(app.handle())?;
    } else {
        log::info!("tray disabled by desktop-config.json — skipping registration");
    }

    // 3. Phase 3 stubs — initialise deep-link + notification + shortcut
    //    subsystems. Real logic lands with Phase 3; today these are pure
    //    log statements so we can verify the wiring without shipping the
    //    plumbing.
    #[cfg(feature = "phase3")]
    {
        deep_link::init(app.handle())?;
        notification::init(app.handle())?;
        shortcut::init(app.handle())?;
    }

    // 4. Wire IPC listeners the renderer will fire against us. Right now
    //    these are all stubs — the real handlers land alongside the menu
    //    subagent's `native-menu.ts` bridge in Phase 2b.
    setup_ipc_listeners(app.handle());

    Ok(())
}

/// Attaches every IPC listener the renderer emits into. Split out from
/// [`setup`] so tests can call it against a mock `AppHandle`.
///
/// Right now we listen for:
///
/// - `locale-changed` — fired by the SPA's `LocaleProvider` when the user
///   swaps language. Phase 2b will translate every menu item title in
///   response; today we only log so the wiring is testable.
/// - `welcome-window-requested` — fired by the onboarding flow when it
///   needs the shell to focus / raise a welcome window. Phase 3 land.
fn setup_ipc_listeners(app: &AppHandle) {
    let app_handle = app.clone();
    app.listen("locale-changed", move |event| {
        log::info!(
            "locale-changed event received: {} — Phase 2b will retranslate menu titles",
            event.payload()
        );
        // Phase 2b TODO: iterate the menu items and call
        // `menu_item.set_text(&translated)`. See menus module
        let _ = &app_handle;
    });

    let app_handle = app.clone();
    app.listen("welcome-window-requested", move |event| {
        log::info!(
            "welcome-window-requested event received — Phase 3 will raise/focus welcome window. payload={}",
            event.payload()
        );
        let _ = &app_handle;
    });
}

/// Called after every top-level Tauri run-loop event. We use it to log
/// noteworthy lifecycle events; production code that needs to react to
/// `RunEvent::ExitRequested` (e.g. save state before quit) should extend
/// this function rather than adding an `on_window_event` on every window.
fn on_run_event<R: tauri::Runtime>(_app: &tauri::AppHandle<R>, event: RunEvent) {
    match event {
        RunEvent::Ready => log::info!("desktop shell ready"),
        RunEvent::ExitRequested { .. } => log::info!("exit requested"),
        RunEvent::Exit => log::info!("desktop shell exiting"),
        _ => {}
    }
}

/// Convenience: emit a `menu-command` event to every window. Used by both
/// the native menu bar and the tray icon handlers so a renderer only needs
/// to subscribe once.
pub(crate) fn emit_menu_command<R: tauri::Runtime>(
    app: &tauri::AppHandle<R>,
    id: impl Into<String>,
    source: &'static str,
) {
    let payload = MenuCommandPayload {
        id: id.into(),
        source,
    };
    if let Err(err) = app.emit("menu-command", &payload) {
        log::warn!("failed to emit menu-command {:?}: {err}", payload);
    }
}
